// 1. Implement IIconProvider
public class MyAppIconProvider : IIconProvider
{
    private readonly Dictionary<string, string> _icons = new(StringComparer.OrdinalIgnoreCase)
    {
        ["app-dashboard"] = "<rect x='3' y='3' width='7' height='7'/><rect x='14' y='3' width='7' height='7'/><rect x='3' y='14' width='7' height='7'/><rect x='14' y='14' width='7' height='7'/>",
        ["app-reports"]   = "<path d='M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z'/>"
    };

    public string? GetSvg(string iconName) =>
        _icons.TryGetValue(iconName, out var svg) ? svg : null;

    public bool HasIcon(string iconName) =>
        _icons.ContainsKey(iconName);
}

// 2. Register in Program.cs
IconRegistry.RegisterProvider(new MyAppIconProvider());
